X_Tick_text = cell(1, length(N_vector));
for i_N = 1:length(N_vector)
    X_Tick_text{i_N} = strcat('$', num2str(N_x_vector(i_N)), '\times', ...
        num2str(N_y_vector(i_N)), '$');
end

