    '\times', num2str(T_y_vector(i_T_init)), '$');

% Intermediate curves: plain solid lines, no special marker
for i_T = 2:length(T_vector)-1
    plot(prc95(:, i_T), '-', 'LineWidth', 2); %[output:4e2db529]
end

% Last curve: T_upd = 12x12 (largest), solid diamond — highlighted
p2 = plot(prc95(:, length(T_vector)), '-d', ... %[output:4e2db529]
    'LineWidth', 2, 'MarkerSize', 8); %[output:4e2db529]
legend_text{2} = strcat('$T_\mathrm{upd}=', num2str(T_x_vector(length(T_vector))), ...
    '\times', num2str(T_y_vector(length(T_vector))), '$');

% % Annotation arrow + label (same style as A_Master_File.m)
% annotation('arrow', [0.35 0.55], [0.65 0.45], ...
